      fetch_strategy: "download_image",
      method: "GET",
      url: "https://www.eastbrunswick.org/ImageRepository/Document?documentId=11258",
      date: today
    }
  },
  {
    json: {
      rink_hint: "East Brunswick",
      type_hint: "freestyle",
      source_type: "html",
      fetch_strategy: "fetch_html",
      method: "GET",
      url: "https://www.eastbrunswick.org/1028/Figure-Skating",
      date: today
    }
  },
  {
    json: {
      rink_hint: "Bridgewater",
      type_hint: "all",
      source_type: "api",
      fetch_strategy: "call_api",
      method: "GET",
      url: `https://api.daysmartrecreation.com/v1/events?cache[save]=false&page[size]=25&sort=start&company=rocketssports&filter[start__gte]=${today}%2000%3A00%3A00&filter[start__lte]=${today}%2023%3A59%3A59&filter[resource.facility.my_sam_visible]=true&filter[eventType.code__not]=L&filterRelations[comments.comment_type]=public&include=homeTeam.league.programType%2CvisitingTeam.league.programType%2Csummary%2Cresource.facility%2CresourceArea%2Ccomments%2CeventType`,
      date: today
    }
  },
  {
