      type_hint: "public",
      source_type: "image",
      fetch_strategy: "download_image",
      method: "GET",
      url: "https://cdn.prod.website-files.com/651bfe9ec1ae3ff7be4eca12/69f4a8ec38ba7c83a1e8db81_May%20Public%20Skate.png",
      date: today
    }
