];

const sourceItems = $('Sources List').all();
const fetchedItems = $input.all();

return fetchedItems.map((item, index) => {
  const source = sourceItems[index]?.json || {};

  return {
    json: {
      ...source,
      fetched_json: item.json,
    },
    binary: item.binary,
  };
});

let response = $json.fetched_json?.data || $json.fetched_json;

if (typeof response === "string") {
  response = JSON.parse(response);
}

const events = response.data || [];
const sessions = [];

for (const event of events) {
  const attr = event.attributes || {};
  const desc = (attr.desc || attr.description || "").toLowerCase();

  if (desc.includes("takedown")) continue;

  let type = null;
  if (desc.includes("freestyle")) type = "freestyle";
  if (desc.includes("public skate")) type = "public";

  if (!type) continue;
  if (!attr.start || !attr.end) continue;

  sessions.push({
    rink: "Bridgewater",
    type,
    date: attr.start.split("T")[0],
    start_time: attr.start.split("T")[1].slice(0, 5),
    end_time: attr.end.split("T")[1].slice(0, 5),
  });
}

return sessions.map(s => ({ json: s }));

const sessions = [];

// 直接从两个上游 node 取完整数据
const bridgewaterItems = $('Parse Bridgewater API').all();
const aiItems = $('AI Agent6').all();

// 1. Bridgewater 已经是标准格式
for (const item of bridgewaterItems) {
  const s = item.json;
  if (s.rink && s.type && s.start_time && s.end_time) {
    sessions.push(s);
  }
}

// 2. AI Agent6 的 output 是 JSON string
for (const item of aiItems) {
  let raw = item.json.output;

  if (typeof raw === "string") {
    try {
      raw = JSON.parse(raw);
    } catch (e) {
      raw = [];
    }
  }

  if (Array.isArray(raw)) {
    for (const s of raw) {
      if (s.rink && s.type && s.start_time && s.end_time) {
        sessions.push(s);
      }
    }
  }
}

// 排序
sessions.sort((a, b) =>
  `${a.date} ${a.start_time}`.localeCompare(`${b.date} ${b.start_time}`)
);

// 输出成多行 item
return sessions.map(s => ({
  json: {
    rink: s.rink,
    type: s.type,
    date: s.date,
    start_time: s.start_time,
    end_time: s.end_time
  }
}));

const sessions = $input.all().map(i => i.json);

const validSessions = sessions.filter(s =>
  s.rink &&
  s.start_time &&
  s.end_time
);

return [
  {
    json: {
      sessions: validSessions
    }
  }
];
